-- ----------------------------------------------------------------------------
-- Users: Bank employees: relationship managers, underwriters, branch bankers, and admins. Used for portfolio assignment, audit trails, and segregation-of-duties enforcement.
-- ----------------------------------------------------------------------------
CREATE TABLE users (
  users_id                            TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: Users had no field named 'Id' or ending in 'Id').
  full_name                           TEXT                ,                     -- Display label of the bank employee.
  role                                TEXT                ,                     -- Role discriminator: RM, Underwriter, BranchBanker, or Admin.
  email                               TEXT                                      -- Bank email used for SSO and notifications.
);
COMMENT ON TABLE users IS 'Bank employees: relationship managers, underwriters, branch bankers, and admins. Used for portfolio assignment, audit trails, and segregation-of-duties enforcement.';
COMMENT ON COLUMN users.users_id IS 'Primary key (auto-synthesized: Users had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN users.full_name IS 'Display label of the bank employee.';
COMMENT ON COLUMN users.role IS 'Role discriminator: RM, Underwriter, BranchBanker, or Admin.';
COMMENT ON COLUMN users.email IS 'Bank email used for SSO and notifications.';

-- ----------------------------------------------------------------------------
-- Businesses: Small-business customers (and prospects) of the bank. Central entity: BeneficialOwners, Contacts, Accounts, Loans, Documents, and Interactions all hang off a Business. BusinessProfile information (legal name, structure, NAICS code) lives directly on this table.
-- ----------------------------------------------------------------------------
CREATE TABLE businesses (
  businesses_id                       TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: Businesses had no field named 'Id' or ending in 'Id').
  legal_name                          TEXT                ,                     -- Registered legal name of the business.
  business_structure                  TEXT                ,                     -- Entity structure: LLC, C-Corp, S-Corp, Partnership, Sole Proprietor, etc.
  naics_code                          TEXT                ,                     -- North American Industry Classification System code for the business.
  naics_description                   TEXT                ,                     -- Human-readable label for the NAICS code.
  annual_revenue_usd                  NUMERIC             ,                     -- Most-recent annual revenue, USD.
  status                              TEXT                ,                     -- Lifecycle status: Prospect, Customer, or Closed.
  onboarded_at                        TIMESTAMPTZ         ,                     -- Date onboarding completed (KYB cleared, first account opened).
  relationship_manager                TEXT                ,                     -- FK to Users: the RM who owns this business relationship (the SinglePointOfContact).
  referral_source                     TEXT                                      -- Optional FK to another Business that referred this prospect/customer in.
);
COMMENT ON TABLE businesses IS 'Small-business customers (and prospects) of the bank. Central entity: BeneficialOwners, Contacts, Accounts, Loans, Documents, and Interactions all hang off a Business. BusinessProfile information (legal name, structure, NAICS code) lives directly on this table.';
COMMENT ON COLUMN businesses.businesses_id IS 'Primary key (auto-synthesized: Businesses had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN businesses.legal_name IS 'Registered legal name of the business.';
COMMENT ON COLUMN businesses.business_structure IS 'Entity structure: LLC, C-Corp, S-Corp, Partnership, Sole Proprietor, etc.';
COMMENT ON COLUMN businesses.naics_code IS 'North American Industry Classification System code for the business.';
COMMENT ON COLUMN businesses.naics_description IS 'Human-readable label for the NAICS code.';
COMMENT ON COLUMN businesses.annual_revenue_usd IS 'Most-recent annual revenue, USD.';
COMMENT ON COLUMN businesses.status IS 'Lifecycle status: Prospect, Customer, or Closed.';
COMMENT ON COLUMN businesses.onboarded_at IS 'Date onboarding completed (KYB cleared, first account opened).';
COMMENT ON COLUMN businesses.relationship_manager IS 'FK to Users: the RM who owns this business relationship (the SinglePointOfContact).';
COMMENT ON COLUMN businesses.referral_source IS 'Optional FK to another Business that referred this prospect/customer in.';

-- ----------------------------------------------------------------------------
-- BeneficialOwners: Individuals owning 25%+ of a Business plus designated control persons, per FinCEN's CDD rule. PII (SSN, DOB, address) is stored encrypted at rest via field-level encryption.
-- ----------------------------------------------------------------------------
CREATE TABLE beneficial_owners (
  beneficial_owners_id                TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: BeneficialOwners had no field named 'Id' or ending in 'Id').
  business                            TEXT                ,                     -- FK to the parent Business.
  full_name                           TEXT                ,                     -- Owner's full legal name.
  date_of_birth_encrypted             TEXT                ,                     -- Encrypted date of birth (PII, FieldLevelEncryption).
  ssn_encrypted                       TEXT                ,                     -- Encrypted Social Security Number (PII, FieldLevelEncryption).
  address_encrypted                   TEXT                ,                     -- Encrypted home address (PII, FieldLevelEncryption).
  ownership_percentage                NUMERIC             ,                     -- Percent of the Business owned by this individual (0-100).
  is_control_person                   BOOLEAN                                   -- True when this individual is the designated control person per CDD (one is required when no owner crosses 25%).
);
COMMENT ON TABLE beneficial_owners IS 'Individuals owning 25%+ of a Business plus designated control persons, per FinCEN''s CDD rule. PII (SSN, DOB, address) is stored encrypted at rest via field-level encryption.';
COMMENT ON COLUMN beneficial_owners.beneficial_owners_id IS 'Primary key (auto-synthesized: BeneficialOwners had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN beneficial_owners.business IS 'FK to the parent Business.';
COMMENT ON COLUMN beneficial_owners.full_name IS 'Owner''s full legal name.';
COMMENT ON COLUMN beneficial_owners.date_of_birth_encrypted IS 'Encrypted date of birth (PII, FieldLevelEncryption).';
COMMENT ON COLUMN beneficial_owners.ssn_encrypted IS 'Encrypted Social Security Number (PII, FieldLevelEncryption).';
COMMENT ON COLUMN beneficial_owners.address_encrypted IS 'Encrypted home address (PII, FieldLevelEncryption).';
COMMENT ON COLUMN beneficial_owners.ownership_percentage IS 'Percent of the Business owned by this individual (0-100).';
COMMENT ON COLUMN beneficial_owners.is_control_person IS 'True when this individual is the designated control person per CDD (one is required when no owner crosses 25%).';

-- ----------------------------------------------------------------------------
-- Contacts: Non-owner individuals associated with a Business: officers, AP clerks, authorized signers, additional points of contact. Distinct from BeneficialOwners (which carries PII/CDD weight).
-- ----------------------------------------------------------------------------
CREATE TABLE contacts (
  contacts_id                         TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: Contacts had no field named 'Id' or ending in 'Id').
  business                            TEXT                ,                     -- FK to the parent Business.
  full_name                           TEXT                ,                     -- Contact's full name.
  title                               TEXT                ,                     -- Job title at the business (CEO, CFO, AP Clerk, etc.).
  email                               TEXT                ,                     -- Contact email.
  phone                               TEXT                ,                     -- Contact phone.
  contact_type                        TEXT                ,                     -- Discriminator: Officer, APClerk, AuthorizedSigner, Other.
  is_authorized_signer                BOOLEAN                                   -- True when this contact can sign on the business's accounts.
);
COMMENT ON TABLE contacts IS 'Non-owner individuals associated with a Business: officers, AP clerks, authorized signers, additional points of contact. Distinct from BeneficialOwners (which carries PII/CDD weight).';
COMMENT ON COLUMN contacts.contacts_id IS 'Primary key (auto-synthesized: Contacts had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN contacts.business IS 'FK to the parent Business.';
COMMENT ON COLUMN contacts.full_name IS 'Contact''s full name.';
COMMENT ON COLUMN contacts.title IS 'Job title at the business (CEO, CFO, AP Clerk, etc.).';
COMMENT ON COLUMN contacts.email IS 'Contact email.';
COMMENT ON COLUMN contacts.phone IS 'Contact phone.';
COMMENT ON COLUMN contacts.contact_type IS 'Discriminator: Officer, APClerk, AuthorizedSigner, Other.';
COMMENT ON COLUMN contacts.is_authorized_signer IS 'True when this contact can sign on the business''s accounts.';

-- ----------------------------------------------------------------------------
-- Accounts: Deposit accounts the Business holds at the bank (checking, savings, money market). Balances feed GlobalCashFlow during credit analysis. TreasuryServices enrollment flags (ACH, Wire, Card) are stored per-account.
-- ----------------------------------------------------------------------------
CREATE TABLE accounts (
  accounts_id                         TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: Accounts had no field named 'Id' or ending in 'Id').
  business                            TEXT                ,                     -- FK to the parent Business.
  account_type                        TEXT                ,                     -- Checking, Savings, MoneyMarket, etc.
  account_number_last4                TEXT                ,                     -- Last 4 digits of the account number for display.
  current_balance_usd                 NUMERIC             ,                     -- Current balance in USD; sourced from CoreBanking.
  has_ach                             BOOLEAN             ,                     -- ACH treasury service enrolled on this account.
  has_wire                            BOOLEAN             ,                     -- Wire transfer treasury service enrolled on this account.
  has_card                            BOOLEAN             ,                     -- Business card product issued against this account.
  opened_at                           TIMESTAMPTZ                               -- Date the account was opened.
);
COMMENT ON TABLE accounts IS 'Deposit accounts the Business holds at the bank (checking, savings, money market). Balances feed GlobalCashFlow during credit analysis. TreasuryServices enrollment flags (ACH, Wire, Card) are stored per-account.';
COMMENT ON COLUMN accounts.accounts_id IS 'Primary key (auto-synthesized: Accounts had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN accounts.business IS 'FK to the parent Business.';
COMMENT ON COLUMN accounts.account_type IS 'Checking, Savings, MoneyMarket, etc.';
COMMENT ON COLUMN accounts.account_number_last4 IS 'Last 4 digits of the account number for display.';
COMMENT ON COLUMN accounts.current_balance_usd IS 'Current balance in USD; sourced from CoreBanking.';
COMMENT ON COLUMN accounts.has_ach IS 'ACH treasury service enrolled on this account.';
COMMENT ON COLUMN accounts.has_wire IS 'Wire transfer treasury service enrolled on this account.';
COMMENT ON COLUMN accounts.has_card IS 'Business card product issued against this account.';
COMMENT ON COLUMN accounts.opened_at IS 'Date the account was opened.';

-- ----------------------------------------------------------------------------
-- Loans: Credit facilities extended to a Business, tracked from inquiry through funding, servicing, and payoff. RiskRating is denormalized here for fast reads; every change is captured in RiskRatingHistory.
-- ----------------------------------------------------------------------------
CREATE TABLE loans (
  loans_id                            TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: Loans had no field named 'Id' or ending in 'Id').
  loan_number                         TEXT                ,                     -- Bank-assigned loan number (e.g. 'L-0051').
  business                            TEXT                ,                     -- FK to the borrower Business.
  originating_rm                      TEXT                ,                     -- FK to Users: the RM who originated this loan.
  underwriter                         TEXT                ,                     -- FK to Users: the underwriter who underwrote this loan.
  loan_purpose                        TEXT                ,                     -- Equipment, CRE, LOC, WorkingCapital, etc.
  principal_usd                       NUMERIC             ,                     -- Loan principal at origination, USD.
  rate_pct                            NUMERIC             ,                     -- Interest rate, percent (e.g. 7.25).
  term_months                         INTEGER             ,                     -- Loan term in months.
  underwriting_stage                  TEXT                ,                     -- Current pipeline stage: Inquiry, PreQualification, Application, KYBAndBureauPull, Packaging, CreditAnalysis, CommitteeApproval, ClosingPrep, Signing, Funded.
  risk_rating                         INTEGER             ,                     -- Current risk grade (1=Pass strongest ... 7=Substandard ... 9=Loss). Denormalized; every change is captured in RiskRatingHistory.
  risk_rating_label                   TEXT                ,                     -- Human-readable label for the current risk grade.
  dscr                                NUMERIC             ,                     -- Most recent debt service coverage ratio.
  ltv                                 NUMERIC             ,                     -- Most recent loan-to-value ratio (0-1); null for unsecured loans.
  global_cash_flow_usd                NUMERIC             ,                     -- Most recent global cash flow figure across business, owners, and affiliates.
  originated_at                       TIMESTAMPTZ         ,                     -- Date the application was created.
  funded_at                           TIMESTAMPTZ                               -- Date the loan funded; null until funding completes.
);
COMMENT ON TABLE loans IS 'Credit facilities extended to a Business, tracked from inquiry through funding, servicing, and payoff. RiskRating is denormalized here for fast reads; every change is captured in RiskRatingHistory.';
COMMENT ON COLUMN loans.loans_id IS 'Primary key (auto-synthesized: Loans had no field named ''Id'' or ending in ''Id'').';
