COMMENT ON COLUMN loans.underwriter IS 'FK to Users: the underwriter who underwrote this loan.';
COMMENT ON COLUMN loans.loan_purpose IS 'Equipment, CRE, LOC, WorkingCapital, etc.';
COMMENT ON COLUMN loans.principal_usd IS 'Loan principal at origination, USD.';
COMMENT ON COLUMN loans.rate_pct IS 'Interest rate, percent (e.g. 7.25).';
COMMENT ON COLUMN loans.term_months IS 'Loan term in months.';
COMMENT ON COLUMN loans.underwriting_stage IS 'Current pipeline stage: Inquiry, PreQualification, Application, KYBAndBureauPull, Packaging, CreditAnalysis, CommitteeApproval, ClosingPrep, Signing, Funded.';
COMMENT ON COLUMN loans.risk_rating IS 'Current risk grade (1=Pass strongest ... 7=Substandard ... 9=Loss). Denormalized; every change is captured in RiskRatingHistory.';
