-- ----------------------------------------------------------------------------
-- Covenants: Conditions attached to a Loan that must be tested on a recurring schedule (e.g. minimum DSCR each quarter). CovenantMonitoring runs the tickler calendar ahead of NextTestDate; breaches surface as SystemEvent Interactions.
-- ----------------------------------------------------------------------------
CREATE TABLE covenants (
  covenants_id                        TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: Covenants had no field named 'Id' or ending in 'Id').
  loan                                TEXT                ,                     -- FK to the parent Loan.
  covenant_type                       TEXT                ,                     -- MinDSCR, MaxLeverage, ReportingFinancials, etc.
  threshold_value                     NUMERIC             ,                     -- Numeric threshold for the test (e.g. 1.20 for MinDSCR); null for non-numeric covenants.
  test_frequency                      TEXT                ,                     -- Quarterly, Annual, Monthly, etc.
  next_test_date                      TIMESTAMPTZ         ,                     -- Date of the next scheduled covenant test.
  status                              TEXT                ,                     -- Active, Breached, Waived, Cured, Closed.
  current_waiver_through              TIMESTAMPTZ                               -- Date through which an active CovenantWaiver is in effect; null when no active waiver.
);
COMMENT ON TABLE covenants IS 'Conditions attached to a Loan that must be tested on a recurring schedule (e.g. minimum DSCR each quarter). CovenantMonitoring runs the tickler calendar ahead of NextTestDate; breaches surface as SystemEvent Interactions.';
COMMENT ON COLUMN covenants.covenants_id IS 'Primary key (auto-synthesized: Covenants had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN covenants.loan IS 'FK to the parent Loan.';
COMMENT ON COLUMN covenants.covenant_type IS 'MinDSCR, MaxLeverage, ReportingFinancials, etc.';
COMMENT ON COLUMN covenants.threshold_value IS 'Numeric threshold for the test (e.g. 1.20 for MinDSCR); null for non-numeric covenants.';
COMMENT ON COLUMN covenants.test_frequency IS 'Quarterly, Annual, Monthly, etc.';
COMMENT ON COLUMN covenants.next_test_date IS 'Date of the next scheduled covenant test.';
COMMENT ON COLUMN covenants.status IS 'Active, Breached, Waived, Cured, Closed.';
COMMENT ON COLUMN covenants.current_waiver_through IS 'Date through which an active CovenantWaiver is in effect; null when no active waiver.';

-- ----------------------------------------------------------------------------
-- RiskRatingHistory: Time-series of risk-grade changes on a Loan. Regulators audit rating drift, so every migration is captured here. AnnualReview also writes a row even when the grade is reaffirmed unchanged.
-- ----------------------------------------------------------------------------
CREATE TABLE risk_rating_history (
  risk_rating_history_id              TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: RiskRatingHistory had no field named 'Id' or ending in 'Id').
  loan                                TEXT                ,                     -- FK to the Loan whose grade changed.
  changed_by_user                     TEXT                ,                     -- FK to Users: who recorded the migration.
  effective_date                      TIMESTAMPTZ         ,                     -- Date the new grade takes effect.
  prior_grade                         INTEGER             ,                     -- Grade before this change; null on initial rating.
  new_grade                           INTEGER             ,                     -- Grade after this change.
  reason                              TEXT                                      -- Free-text justification for the migration.
);
COMMENT ON TABLE risk_rating_history IS 'Time-series of risk-grade changes on a Loan. Regulators audit rating drift, so every migration is captured here. AnnualReview also writes a row even when the grade is reaffirmed unchanged.';
COMMENT ON COLUMN risk_rating_history.risk_rating_history_id IS 'Primary key (auto-synthesized: RiskRatingHistory had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN risk_rating_history.loan IS 'FK to the Loan whose grade changed.';
COMMENT ON COLUMN risk_rating_history.changed_by_user IS 'FK to Users: who recorded the migration.';
COMMENT ON COLUMN risk_rating_history.effective_date IS 'Date the new grade takes effect.';
COMMENT ON COLUMN risk_rating_history.prior_grade IS 'Grade before this change; null on initial rating.';
COMMENT ON COLUMN risk_rating_history.new_grade IS 'Grade after this change.';
COMMENT ON COLUMN risk_rating_history.reason IS 'Free-text justification for the migration.';

-- ----------------------------------------------------------------------------
-- Documents: Files in the DocumentVault. A document attaches to either a Business (tax returns, formation docs) or a Loan (note, security agreement, appraisal). Both FKs are nullable so a document can hang off the appropriate parent.
-- ----------------------------------------------------------------------------
CREATE TABLE documents (
  documents_id                        TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: Documents had no field named 'Id' or ending in 'Id').
  business                            TEXT                ,                     -- Optional FK to a Business (nullable for loan-only docs).
  loan                                TEXT                ,                     -- Optional FK to a Loan (nullable for business-only docs).
  uploaded_by_user                    TEXT                ,                     -- Optional FK to the User who uploaded (null when uploaded via the BusinessClientPortal).
  filename                            TEXT                ,                     -- Original filename in the vault.
  document_type                       TEXT                ,                     -- TaxReturn, FormationDoc, FinancialStatement, Note, SecurityAgreement, Appraisal, etc.
  ocr_indexed                         BOOLEAN             ,                     -- True once OCR has indexed the document into SearchAndIndexing.
  uploaded_via                        TEXT                ,                     -- Source surface: RMDashboard, BranchBankerPortal, BusinessClientPortal, AdminConsole, API.
  uploaded_at                         TIMESTAMPTZ                               -- Upload timestamp.
);
COMMENT ON TABLE documents IS 'Files in the DocumentVault. A document attaches to either a Business (tax returns, formation docs) or a Loan (note, security agreement, appraisal). Both FKs are nullable so a document can hang off the appropriate parent.';
COMMENT ON COLUMN documents.documents_id IS 'Primary key (auto-synthesized: Documents had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN documents.business IS 'Optional FK to a Business (nullable for loan-only docs).';
COMMENT ON COLUMN documents.loan IS 'Optional FK to a Loan (nullable for business-only docs).';
COMMENT ON COLUMN documents.uploaded_by_user IS 'Optional FK to the User who uploaded (null when uploaded via the BusinessClientPortal).';
COMMENT ON COLUMN documents.filename IS 'Original filename in the vault.';
COMMENT ON COLUMN documents.document_type IS 'TaxReturn, FormationDoc, FinancialStatement, Note, SecurityAgreement, Appraisal, etc.';
COMMENT ON COLUMN documents.ocr_indexed IS 'True once OCR has indexed the document into SearchAndIndexing.';
COMMENT ON COLUMN documents.uploaded_via IS 'Source surface: RMDashboard, BranchBankerPortal, BusinessClientPortal, AdminConsole, API.';
COMMENT ON COLUMN documents.uploaded_at IS 'Upload timestamp.';

-- ----------------------------------------------------------------------------
-- Interactions: Unified activity-log feed for a Business. An Interaction is intentionally generic: InteractionType discriminates Note, Call, Visit, Task, Meeting, or SystemEvent. Covenant breaches, document requests, and other machine actions are written as SystemEvent interactions so they appear in the same stream as human-logged activity.
-- ----------------------------------------------------------------------------
CREATE TABLE interactions (
  interactions_id                     TEXT                 PRIMARY KEY,         -- Primary key (auto-synthesized: Interactions had no field named 'Id' or ending in 'Id').
  business                            TEXT                ,                     -- FK to the parent Business.
  "user"                              TEXT                ,                     -- FK to Users: who logged the interaction (null for system-generated or customer-portal-originated rows).
  interaction_type                    TEXT                ,                     -- Note, Call, Visit, Task, Meeting, or SystemEvent.
  subject                             TEXT                ,                     -- Short subject line (used in compound PK).
  body                                TEXT                ,                     -- Long-form body of the interaction.
  interaction_date                    TIMESTAMPTZ         ,                     -- Date the interaction occurred or was logged.
  due_date                            TIMESTAMPTZ         ,                     -- For Task-type interactions: due date.
  source                              TEXT                                      -- Origin surface: RMDashboard, BusinessClientPortal, BranchBankerPortal, SystemEvent.
);
COMMENT ON TABLE interactions IS 'Unified activity-log feed for a Business. An Interaction is intentionally generic: InteractionType discriminates Note, Call, Visit, Task, Meeting, or SystemEvent. Covenant breaches, document requests, and other machine actions are written as SystemEvent interactions so they appear in the same stream as human-logged activity.';
COMMENT ON COLUMN interactions.interactions_id IS 'Primary key (auto-synthesized: Interactions had no field named ''Id'' or ending in ''Id'').';
COMMENT ON COLUMN interactions.business IS 'FK to the parent Business.';
COMMENT ON COLUMN interactions."user" IS 'FK to Users: who logged the interaction (null for system-generated or customer-portal-originated rows).';
COMMENT ON COLUMN interactions.interaction_type IS 'Note, Call, Visit, Task, Meeting, or SystemEvent.';
COMMENT ON COLUMN interactions.subject IS 'Short subject line (used in compound PK).';
COMMENT ON COLUMN interactions.body IS 'Long-form body of the interaction.';
COMMENT ON COLUMN interactions.interaction_date IS 'Date the interaction occurred or was logged.';
COMMENT ON COLUMN interactions.due_date IS 'For Task-type interactions: due date.';
COMMENT ON COLUMN interactions.source IS 'Origin surface: RMDashboard, BusinessClientPortal, BranchBankerPortal, SystemEvent.';

